// ============================================================
// בדיקת מפתח API
// ============================================================
const apiKey = $input.first().json.headers['x-api-key'];
const SECRET_KEY = 'YOUR_SECRET_API_KEY'; // <-- שנה למפתח שלך

if (apiKey !== SECRET_KEY) {
  return [{
    json: {
      __statusCode: 401,
      error: 'Unauthorized'
    }
  }];
}

// ============================================================
// רשימת נהגים — ערוך לפי הצורך
// ============================================================
